import{_ as a,o as e,c as o,a2 as r}from"./chunks/framework.Crpw6aS5.js";const m=JSON.parse('{"title":"金句 · 按主题","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-theme/index.md","filePath":"05_quotes/by-theme/index.md"}'),d={name:"05_quotes/by-theme/index.md"};function h(n,t,c,l,s,i){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="金句-·-按主题" tabindex="-1">金句 · 按主题 <a class="header-anchor" href="#金句-·-按主题" aria-label="Permalink to &quot;金句 · 按主题&quot;">​</a></h1><blockquote><p>巴菲特70年投资哲学的核心主题分类，每个主题下是最有力量的一句话。</p></blockquote><hr><h2 id="💡-投资哲学" tabindex="-1">💡 投资哲学 <a class="header-anchor" href="#💡-投资哲学" aria-label="Permalink to &quot;💡 投资哲学&quot;">​</a></h2><table tabindex="0"><thead><tr><th>主题</th><th>经典金句</th></tr></thead><tbody><tr><td><a href="/02_concepts/intrinsic-value.html">内在价值</a></td><td>&quot;内在价值是一个企业从现在到清算日能产生的现金流折现值。它不是一个精确的数字，而是一个估计区间。&quot;</td></tr><tr><td><a href="/02_concepts/moat.html">护城河</a></td><td>&quot;经济城堡周围的护城河，是抵御竞争的持久优势。&quot;</td></tr><tr><td><a href="/02_concepts/safety-margin.html">安全边际</a></td><td>&quot;投资的全部意义在于，在好公司以合理价格买入。但合理价格远低于内在价值时买入，就是安全边际。&quot;</td></tr><tr><td><a href="/02_concepts/compounding.html">复利</a></td><td>&quot;复利是神奇的力量，是世界第八大奇迹。理解它的人赚取它，不理解的人支付它。&quot;</td></tr><tr><td><a href="/02_concepts/long-term.html">长期主义</a></td><td>&quot;如果你不打算持有一只股票十年，那连持有十分钟都不要考虑。&quot;</td></tr><tr><td><a href="/02_concepts/circle-of-competence.html">能力圈</a></td><td>&quot;知道你不知道什么，比你知道什么更重要。在你的能力圈内行动，在能力圈外保持静止。&quot;</td></tr><tr><td><a href="/02_concepts/contrarian.html">逆向思维</a></td><td>&quot;在别人恐惧时贪婪，在别人贪婪时恐惧。这句话所有人都知道，但做到需要勇气。&quot;</td></tr></tbody></table><h2 id="⚙️-商业逻辑" tabindex="-1">⚙️ 商业逻辑 <a class="header-anchor" href="#⚙️-商业逻辑" aria-label="Permalink to &quot;⚙️ 商业逻辑&quot;">​</a></h2><table tabindex="0"><thead><tr><th>主题</th><th>经典金句</th></tr></thead><tbody><tr><td><a href="/02_concepts/insurance-float.html">保险浮存金</a></td><td>&quot;浮存金是伯克希尔最重要的低成本资金来源，这是我们相对于其他保险公司最核心的结构性优势。&quot;</td></tr><tr><td><a href="/02_concepts/underwriting-discipline.html">承保纪律</a></td><td>&quot;保险业务成功的关键是：永远不要用不合理的价格换取保费规模。宁可少做业务，也要守住承保纪律。&quot;</td></tr><tr><td><a href="/02_concepts/capital-allocation.html">资本配置</a></td><td>&quot;资本配置是CEO最重要的职责，也是区分优秀管理者和普通管理者的核心能力。&quot;</td></tr><tr><td><a href="/02_concepts/share-buybacks.html">股票回购</a></td><td>&quot;只有在股票远低于内在价值时，回购才有意义。回购不应该只是为了&quot;用掉&quot;现金。&quot;</td></tr><tr><td><a href="/02_concepts/reputation.html">声誉</a></td><td>&quot;声誉的建立需要二十年，毁掉它只需要五分钟。&quot;</td></tr></tbody></table><h2 id="🧠-思维方法" tabindex="-1">🧠 思维方法 <a class="header-anchor" href="#🧠-思维方法" aria-label="Permalink to &quot;🧠 思维方法&quot;">​</a></h2><table tabindex="0"><thead><tr><th>主题</th><th>经典金句</th></tr></thead><tbody><tr><td><a href="/02_concepts/risk.html">风险</a></td><td>&quot;风险来自于你不知道自己在做什么。不是波动性带来风险，而是你无知的程度决定风险的大小。&quot;</td></tr><tr><td><a href="/02_concepts/diversification.html">多元化与集中</a></td><td>&quot;多元化投资是一种保护无知的手段。如果你不是专家，多元化就是必要的。但如果你对投资有真正的理解，集中投资反而更合理。&quot;</td></tr></tbody></table><h2 id="🏛️-治理智慧" tabindex="-1">🏛️ 治理智慧 <a class="header-anchor" href="#🏛️-治理智慧" aria-label="Permalink to &quot;🏛️ 治理智慧&quot;">​</a></h2><table tabindex="0"><thead><tr><th>主题</th><th>经典金句</th></tr></thead><tbody><tr><td><a href="/02_concepts/management.html">管理层</a></td><td>&quot;找一个比你更聪明、更有品格的人，然后充分授权。不要干涉他们如何经营业务。&quot;</td></tr><tr><td><a href="/02_concepts/corporate-governance.html">董事会治理</a></td><td>&quot;不要让糟糕的董事会控制你的公司。好董事会的价值，在于能在关键时刻做出正确决策。&quot;</td></tr><tr><td><a href="/02_concepts/executive-compensation.html">高管薪酬</a></td><td>&quot;激励必须与结果挂钩，且简单可衡量。复杂的薪酬方案往往是为了让管理者自我感觉良好，而非真正激励他们。&quot;</td></tr><tr><td><a href="/02_concepts/accounting-earnings.html">GAAP与真实盈利</a></td><td>&quot;会计准则只是商业现实的参考，而非替代。理解一家企业，必须看透数字背后的真实经济含义。&quot;</td></tr></tbody></table><h2 id="📜-历史镜鉴" tabindex="-1">📜 历史镜鉴 <a class="header-anchor" href="#📜-历史镜鉴" aria-label="Permalink to &quot;📜 历史镜鉴&quot;">​</a></h2><table tabindex="0"><thead><tr><th>主题</th><th>经典金句</th></tr></thead><tbody><tr><td><a href="/02_concepts/airline-lessons.html">航空公司教训</a></td><td>&quot;做一个资本密集型、高固定成本的行业，需要极其谨慎。航空公司的历史是投资者资本毁灭的历史。&quot;</td></tr><tr><td><a href="/02_concepts/japan-investments.html">日本五大投资</a></td><td>&quot;我们以极低的价格买入了日本五大综合企业的股票。这些公司现金流充裕、治理保守、以折扣价买入——典型的烟蒂投资。&quot;</td></tr></tbody></table><hr><p><strong>深入阅读 →</strong> <a href="/02_concepts/intrinsic-value.html">内在价值</a> · <a href="/02_concepts/moat.html">护城河</a> · <a href="/02_concepts/safety-margin.html">安全边际</a> · <a href="/02_concepts/compounding.html">复利</a> · <a href="/02_concepts/long-term.html">长期主义</a> · <a href="/02_concepts/circle-of-competence.html">能力圈</a> · <a href="/02_concepts/contrarian.html">逆向思维</a> · <a href="/02_concepts/reputation.html">声誉</a> · <a href="/02_concepts/risk.html">风险</a> · <a href="/02_concepts/capital-allocation.html">资本配置</a> · <a href="/02_concepts/insurance-float.html">保险浮存金</a> · <a href="/02_concepts/management.html">管理层</a> · <a href="/02_concepts/share-buybacks.html">股票回购</a> · <a href="/02_concepts/corporate-governance.html">董事会治理</a> · <a href="/02_concepts/executive-compensation.html">高管薪酬</a> · <a href="/02_concepts/accounting-earnings.html">GAAP与真实盈利</a></p>',15)])])}const p=a(d,[["render",h]]);export{m as __pageData,p as default};
